import type { UserRow, QueueItemRow, ExerciseTemplateMappingRow, RoutineMappingRow, ProgramRow, Program, BenchmarkResultRow } from "../types";
import { sha256Hex, encryptAesGcm } from "../utils/crypto";

export async function getUser(db: D1Database, userId: string): Promise<UserRow | null> {
  return db.prepare("SELECT * FROM users WHERE id = ?").bind(userId).first<UserRow>();
}

export async function upsertUser(
  db: D1Database,
  user: { id: string; active_program: string; template_id: string; start_date: string; hevy_api_key?: string; timezone?: string }
): Promise<void> {
  await db
    .prepare(
      `INSERT INTO users (id, active_program, template_id, start_date, hevy_api_key, timezone)
       VALUES (?, ?, ?, ?, ?, ?)
       ON CONFLICT(id) DO UPDATE SET
         active_program = excluded.active_program,
         template_id = excluded.template_id,
         start_date = excluded.start_date,
         hevy_api_key = COALESCE(excluded.hevy_api_key, users.hevy_api_key),
         timezone = COALESCE(excluded.timezone, users.timezone)`
    )
    .bind(user.id, user.active_program, user.template_id, user.start_date, user.hevy_api_key ?? null, user.timezone ?? null)
    .run();
}

/** Update program fields and return the existing API key in one roundtrip */
export async function updateUserProgram(
  db: D1Database,
  userId: string,
  activeProgram: string,
  templateId: string,
  startDate: string
): Promise<string | null> {
  await db
    .prepare("UPDATE users SET active_program = ?, template_id = ?, start_date = ? WHERE id = ?")
    .bind(activeProgram, templateId, startDate, userId)
    .run();
  const row = await db.prepare("SELECT hevy_api_key FROM users WHERE id = ?").bind(userId).first<{ hevy_api_key: string | null }>();
  return row?.hevy_api_key ?? null;
}

export async function getQueueItems(db: D1Database, userId: string, programId?: number): Promise<QueueItemRow[]> {
  const result = programId != null
    ? await db
        .prepare("SELECT * FROM queue_items WHERE user_id = ? AND program_id = ? ORDER BY position")
        .bind(userId, programId)
        .all<QueueItemRow>()
    : await db
        .prepare("SELECT * FROM queue_items WHERE user_id = ? ORDER BY position")
        .bind(userId)
        .all<QueueItemRow>();
  return result.results;
}

export async function insertQueueItems(
  db: D1Database,
  userId: string,
  items: Array<{ routine_id: string; position: number }>,
  programId?: number
): Promise<void> {
  const stmt = db.prepare(
    "INSERT INTO queue_items (user_id, routine_id, position, program_id) VALUES (?, ?, ?, ?)"
  );
  const batch = items.map((item) => stmt.bind(userId, item.routine_id, item.position, programId ?? null));
  await db.batch(batch);
}

export async function markQueueItemCompleted(
  db: D1Database,
  itemId: number,
  completedDate: string,
  hevyWorkoutId?: string,
  workoutData?: string
): Promise<void> {
  await db
    .prepare(
      "UPDATE queue_items SET status = 'completed', completed_date = ?, hevy_workout_id = ?, hevy_workout_data = ? WHERE id = ?"
    )
    .bind(completedDate, hevyWorkoutId ?? null, workoutData ?? null, itemId)
    .run();
}

/** Batch-mark multiple queue items as completed in a single D1 roundtrip */
export async function batchMarkQueueItemsCompleted(
  db: D1Database,
  items: Array<{ itemId: number; completedDate: string; workoutId: string; workoutData?: string }>
): Promise<void> {
  if (items.length === 0) return;
  await db.batch(
    items.map((item) =>
      db
        .prepare(
          "UPDATE queue_items SET status = 'completed', completed_date = ?, hevy_workout_id = ?, hevy_workout_data = ? WHERE id = ?"
        )
        .bind(item.completedDate, item.workoutId, item.workoutData ?? null, item.itemId)
    )
  );
}

export async function markQueueItemCompletedForUser(
  db: D1Database,
  itemId: number,
  userId: string,
  completedDate: string,
  hevyWorkoutId?: string
): Promise<void> {
  await db
    .prepare(
      "UPDATE queue_items SET status = 'completed', completed_date = ?, hevy_workout_id = ? WHERE id = ? AND user_id = ?"
    )
    .bind(completedDate, hevyWorkoutId ?? null, itemId, userId)
    .run();
}

export async function updateQueueItemHevyRoutineId(
  db: D1Database,
  itemId: number,
  routineId: string
): Promise<void> {
  await db
    .prepare("UPDATE queue_items SET hevy_routine_id = ? WHERE id = ?")
    .bind(routineId, itemId)
    .run();
}

export async function getExerciseTemplateMappings(
  db: D1Database,
  userId: string,
  programId?: number
): Promise<ExerciseTemplateMappingRow[]> {
  const result = programId != null
    ? await db
        .prepare("SELECT * FROM exercise_template_mappings WHERE user_id = ? AND program_id = ?")
        .bind(userId, programId)
        .all<ExerciseTemplateMappingRow>()
    : await db
        .prepare("SELECT * FROM exercise_template_mappings WHERE user_id = ?")
        .bind(userId)
        .all<ExerciseTemplateMappingRow>();
  return result.results;
}

export async function upsertExerciseTemplateMapping(
  db: D1Database,
  mapping: ExerciseTemplateMappingRow
): Promise<void> {
  await db
    .prepare(
      `INSERT INTO exercise_template_mappings (user_id, program_template_id, hevy_template_id, is_custom, program_id)
       VALUES (?, ?, ?, ?, ?)
       ON CONFLICT(user_id, program_template_id) DO UPDATE SET
         hevy_template_id = excluded.hevy_template_id,
         is_custom = excluded.is_custom,
         program_id = excluded.program_id`
    )
    .bind(mapping.user_id, mapping.program_template_id, mapping.hevy_template_id, mapping.is_custom, mapping.program_id ?? null)
    .run();
}

export async function getRoutineMappings(
  db: D1Database,
  userId: string,
  programId?: number
): Promise<RoutineMappingRow[]> {
  const result = programId != null
    ? await db
        .prepare("SELECT * FROM routine_mappings WHERE user_id = ? AND program_id = ?")
        .bind(userId, programId)
        .all<RoutineMappingRow>()
    : await db
        .prepare("SELECT * FROM routine_mappings WHERE user_id = ?")
        .bind(userId)
        .all<RoutineMappingRow>();
  return result.results;
}

export async function upsertRoutineMapping(
  db: D1Database,
  mapping: RoutineMappingRow
): Promise<void> {
  await db
    .prepare(
      `INSERT INTO routine_mappings (user_id, program_routine_id, hevy_routine_id, program_id)
       VALUES (?, ?, ?, ?)
       ON CONFLICT(user_id, program_routine_id) DO UPDATE SET
         hevy_routine_id = excluded.hevy_routine_id,
         program_id = excluded.program_id`
    )
    .bind(mapping.user_id, mapping.program_routine_id, mapping.hevy_routine_id, mapping.program_id ?? null)
    .run();
}

export async function bulkSetQueueItemRoutineIds(
  db: D1Database,
  userId: string,
  routineIdMap: Map<string, string>
): Promise<void> {
  if (routineIdMap.size === 0) return;
  const stmt = db.prepare(
    "UPDATE queue_items SET hevy_routine_id = ? WHERE user_id = ? AND routine_id = ?"
  );
  const batch = [...routineIdMap.entries()].map(([programRoutineId, hevyRoutineId]) =>
    stmt.bind(hevyRoutineId, userId, programRoutineId)
  );
  await db.batch(batch);
}

export async function insertProgram(
  db: D1Database,
  userId: string,
  jsonData: string
): Promise<number> {
  const deactivate = db
    .prepare("UPDATE programs SET is_active = 0 WHERE user_id = ? AND is_active = 1")
    .bind(userId);
  const insert = db
    .prepare("INSERT INTO programs (user_id, json_data) VALUES (?, ?)")
    .bind(userId, jsonData);
  const [, insertResult] = await db.batch([deactivate, insert]);
  const id = insertResult.meta.last_row_id;
  if (id == null) throw new Error(`Failed to insert program for user ${userId}`);
  return id;
}

export async function updateDailyCompleted(
  db: D1Database,
  userId: string,
  date: string
): Promise<void> {
  await db
    .prepare("UPDATE users SET daily_completed_date = ? WHERE id = ?")
    .bind(date, userId)
    .run();
}

export async function getActiveProgram(
  db: D1Database,
  userId: string
): Promise<Pick<ProgramRow, "id" | "json_data" | "current_phase_id" | "phase_advanced_at"> | null> {
  return db
    .prepare(
      `SELECT id, json_data, current_phase_id, phase_advanced_at FROM programs
       WHERE user_id = ? AND is_active = 1
       ORDER BY created_at DESC LIMIT 1`
    )
    .bind(userId)
    .first<Pick<ProgramRow, "id" | "json_data" | "current_phase_id" | "phase_advanced_at">>();
}

export async function updateWebhookState(
  db: D1Database,
  userId: string,
  callbackUrl: string,
  bearerToken: string,
  encryptionKey: string
): Promise<void> {
  const hashed = await sha256Hex(bearerToken);
  const encrypted = await encryptAesGcm(bearerToken, encryptionKey);
  await db
    .prepare("UPDATE users SET webhook_id = ?, webhook_bearer_token = ?, webhook_auth_token = ? WHERE id = ?")
    .bind(callbackUrl, encrypted, hashed, userId)
    .run();
}

export async function clearWebhookState(
  db: D1Database,
  userId: string
): Promise<void> {
  await db
    .prepare("UPDATE users SET webhook_id = NULL, webhook_bearer_token = NULL, webhook_auth_token = NULL WHERE id = ?")
    .bind(userId)
    .run();
}

export async function updateLastSyncAt(
  db: D1Database,
  userId: string,
  timestamp: string
): Promise<void> {
  await db
    .prepare("UPDATE users SET last_sync_at = ? WHERE id = ?")
    .bind(timestamp, userId)
    .run();
}

export async function getUserByWebhookToken(
  db: D1Database,
  authToken: string
): Promise<UserRow | null> {
  const hashed = await sha256Hex(authToken);
  return db
    .prepare("SELECT * FROM users WHERE webhook_auth_token = ?")
    .bind(hashed)
    .first<UserRow>();
}

/** Clear pending queue items and all mappings in a single batch (preserve completed history).
 * When programId is provided, only clears data for that program. */
export async function clearPendingStateForUser(db: D1Database, userId: string, programId?: number): Promise<void> {
  if (programId != null) {
    await db.batch([
      db.prepare("DELETE FROM queue_items WHERE user_id = ? AND program_id = ? AND status = 'pending'").bind(userId, programId),
      db.prepare("DELETE FROM exercise_template_mappings WHERE user_id = ? AND program_id = ?").bind(userId, programId),
      db.prepare("DELETE FROM routine_mappings WHERE user_id = ? AND program_id = ?").bind(userId, programId),
    ]);
  } else {
    await db.batch([
      db.prepare("DELETE FROM queue_items WHERE user_id = ? AND status = 'pending'").bind(userId),
      db.prepare("DELETE FROM exercise_template_mappings WHERE user_id = ?").bind(userId),
      db.prepare("DELETE FROM routine_mappings WHERE user_id = ?").bind(userId),
    ]);
  }
}

/** Return all programs for a user, ordered by creation date descending. */
export async function getPrograms(db: D1Database, userId: string): Promise<ProgramRow[]> {
  const result = await db
    .prepare("SELECT * FROM programs WHERE user_id = ? ORDER BY created_at DESC")
    .bind(userId)
    .all<ProgramRow>();
  return result.results;
}

/** Deactivate all programs for user, then activate the specified one. */
export async function setActiveProgram(db: D1Database, userId: string, programId: number): Promise<void> {
  await db.batch([
    db.prepare("UPDATE programs SET is_active = 0 WHERE user_id = ?").bind(userId),
    db.prepare("UPDATE programs SET is_active = 1 WHERE id = ? AND user_id = ?").bind(programId, userId),
  ]);
}

/** Load the active program from D1 for a given user. Returns the program, its D1 row ID, and current phase ID. */
export async function loadProgram(db: D1Database, userId: string): Promise<{ program: Program; programId: number; currentPhaseId: string | null; phaseAdvancedAt: string | null }> {
  const row = await getActiveProgram(db, userId);
  if (!row) throw new Error("No active program found");
  return { program: JSON.parse(row.json_data) as Program, programId: row.id, currentPhaseId: row.current_phase_id, phaseAdvancedAt: row.phase_advanced_at };
}

/** Advance the current phase for a program. */
export async function advancePhase(
  db: D1Database,
  programId: number,
  newPhaseId: string
): Promise<void> {
  await db
    .prepare("UPDATE programs SET current_phase_id = ?, phase_advanced_at = datetime('now') WHERE id = ?")
    .bind(newPhaseId, programId)
    .run();
}

/** Delete a program and its associated queue items and mappings. */
export async function deleteProgram(db: D1Database, userId: string, programId: number): Promise<void> {
  await db.batch([
    db.prepare("DELETE FROM queue_items WHERE user_id = ? AND program_id = ?").bind(userId, programId),
    db.prepare("DELETE FROM exercise_template_mappings WHERE user_id = ? AND program_id = ?").bind(userId, programId),
    db.prepare("DELETE FROM routine_mappings WHERE user_id = ? AND program_id = ?").bind(userId, programId),
    db.prepare("DELETE FROM skill_assessments WHERE user_id = ? AND program_id = ?").bind(userId, programId),
    db.prepare("DELETE FROM programs WHERE id = ? AND user_id = ?").bind(programId, userId),
  ]);
}

/** Load all skill assessments for a user's active program as a Map<skillId, currentState>. */
export async function getUserSkillAssessments(
  db: D1Database,
  userId: string,
  programId: number
): Promise<Map<string, string>> {
  const result = await db
    .prepare("SELECT skill_id, current_state FROM skill_assessments WHERE user_id = ? AND program_id = ?")
    .bind(userId, programId)
    .all<{ skill_id: string; current_state: string }>();
  return new Map(result.results.map((r) => [r.skill_id, r.current_state]));
}

/** Insert or update a user's skill assessment text. */
export async function upsertSkillAssessment(
  db: D1Database,
  userId: string,
  programId: number,
  skillId: string,
  currentState: string
): Promise<void> {
  await db
    .prepare(
      `INSERT INTO skill_assessments (user_id, program_id, skill_id, current_state)
       VALUES (?, ?, ?, ?)
       ON CONFLICT(user_id, program_id, skill_id) DO UPDATE SET
         current_state = excluded.current_state,
         updated_at = datetime('now')`
    )
    .bind(userId, programId, skillId, currentState)
    .run();
}

/** Insert a single benchmark result. */
export async function insertBenchmarkResult(
  db: D1Database,
  result: {
    userId: string;
    programId: number;
    benchmarkId: string;
    value: string;
    passed: boolean;
    side: string | null;
    notes: string | null;
    testedAt: string;
  }
): Promise<void> {
  await db
    .prepare(
      `INSERT INTO benchmark_results (user_id, program_id, benchmark_id, value, passed, side, notes, tested_at)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?)`
    )
    .bind(
      result.userId,
      result.programId,
      result.benchmarkId,
      result.value,
      result.passed ? 1 : 0,
      result.side,
      result.notes,
      result.testedAt
    )
    .run();
}

/** Load all benchmark results for a user+program, ordered by benchmark then newest first. */
export async function getBenchmarkResults(
  db: D1Database,
  userId: string,
  programId: number
): Promise<BenchmarkResultRow[]> {
  const result = await db
    .prepare(
      `SELECT * FROM benchmark_results
       WHERE user_id = ? AND program_id = ?
       ORDER BY benchmark_id, tested_at DESC`
    )
    .bind(userId, programId)
    .all<BenchmarkResultRow>();
  return result.results;
}

// ──────────────────────────────────────────────────────────────────
// Progress page fragments — skills, roadmap, benchmarks
// ──────────────────────────────────────────────────────────────────

import type { Skill, RoadmapPhase, Benchmark, BenchmarkResultRow } from "../types";
import { escapeHtml, escapeAttr } from "../utils/html";
import { evaluateGateTests, isRetestDue, formatTrend } from "../domain/benchmarks";
import { resolvePhaseStatuses, filterResultsSince } from "../domain/phases";

/**
 * Render a single skill card. Used by skillCards() for the full list,
 * and by the POST handler to patch a single card via SSE.
 */
export function skillCardHtml(
  skill: Skill,
  expanded: boolean,
  assessments?: Map<string, string>
): string {
  const signalName = `skill_${skill.id.replace(/[^a-zA-Z0-9]/g, "_")}`;
  const iconBg = skill.color ? `background:${escapeAttr(skill.color)}22` : "background:rgba(255,255,255,0.06)";
  const iconColor = escapeAttr(skill.color ?? "var(--text)");
  const priorityLabel = skill.priority != null ? `#${skill.priority}` : "";

  const milestonesHtml =
    skill.milestones && skill.milestones.length > 0
      ? `<ul class="milestone-list">${skill.milestones
          .map(
            (m) =>
              `<li class="milestone-item">
  <div class="milestone-dot" style="background:${escapeAttr(skill.color ?? "var(--blue)")}"></div>
  <div>
    <div class="milestone-name">${escapeHtml(m.name)}</div>
    ${m.description ? `<div class="milestone-desc">${escapeHtml(m.description)}</div>` : ""}
    ${m.targetWeek != null ? `<div class="milestone-week">Week ${m.targetWeek}</div>` : ""}
  </div>
</li>`
          )
          .join("")}</ul>`
      : "";

  const currentStateText = assessments?.get(skill.id) ?? skill.currentState;
  const hasCurrentState = !!currentStateText;
  const currentStateHtml = hasCurrentState
    ? `<div class="skill-current-state" id="assess-${escapeAttr(skill.id)}">
  <div class="current-state-label">Where You Are</div>
  <div class="current-state-text">${escapeHtml(currentStateText)}</div>
</div>`
    : "";

  const editSignal = `editing_${signalName}`;
  const textSignal = `assess_${signalName}`;
  const jsText = JSON.stringify(currentStateText ?? "");

  const editHtml = hasCurrentState
    ? `<div class="skill-edit-row" data-show="!$${editSignal}">
  <button class="btn-link" data-on:click="$${editSignal} = true">Edit</button>
</div>
<div class="skill-edit-form" data-show="$${editSignal}">
  <textarea class="form-input" rows="3" data-bind:${textSignal}></textarea>
  <div class="skill-edit-actions">
    <button class="btn btn-blue btn-sm" data-on:click="@post('/api/skill-assessment/${escapeAttr(skill.id)}')">Save</button>
    <button class="btn btn-ghost btn-sm" data-on:click="$${editSignal} = false">Cancel</button>
  </div>
</div>`
    : "";

  const editSignalsAttr = hasCurrentState
    ? ` data-signals:${editSignal}="false" data-signals:${textSignal}="${escapeAttr(jsText)}"`
    : "";

  return `<div class="skill-card" data-signals:${signalName}="${expanded}"${editSignalsAttr}>
  <div class="skill-header" data-on:click="$${signalName} = !$${signalName}">
    <div class="skill-icon" style="${iconBg}; color:${iconColor}">${escapeHtml(skill.icon ?? "")}</div>
    <span class="skill-name">${escapeHtml(skill.name)}</span>
    ${priorityLabel ? `<span class="skill-priority">${escapeHtml(priorityLabel)}</span>` : ""}
  </div>
  <div class="skill-body" data-show="$${signalName}">
    ${currentStateHtml}
    ${editHtml}
    ${skill.timeline ? `<div class="skill-timeline">${escapeHtml(skill.timeline)}</div>` : ""}
    ${milestonesHtml}
  </div>
</div>`;
}

/**
 * Skill cards — expandable cards with icon, name, timeline, priority badge.
 * The first card is expanded by default; others are collapsed.
 * Uses Datastar signals for expand/collapse toggling.
 */
export function skillCards(skills: Skill[], assessments?: Map<string, string>): string {
  if (skills.length === 0) return "";
  const cards = skills.map((skill, index) => skillCardHtml(skill, index === 0, assessments));
  return `<div class="section-header">Skills</div>\n${cards.join("\n")}`;
}

/**
 * Roadmap section — phase list with current phase highlighted and gate test checklist.
 * Gate evaluation for the current phase uses only results logged after phaseAdvancedAt
 * (if set). For Phase 1 (no advancement), all results are used.
 */
export function roadmapSection(
  phases: RoadmapPhase[],
  results: BenchmarkResultRow[],
  benchmarks: Benchmark[],
  currentPhaseId: string | null,
  phaseAdvancedAt?: string | null
): string {
  if (phases.length === 0) return "";

  const resolved = resolvePhaseStatuses(phases, currentPhaseId);
  const currentPhaseResults = filterResultsSince(results, phaseAdvancedAt);

  const items = resolved
    .map((phase) => {
      const isCurrent = phase.status === "current";
      const isCompleted = phase.status === "completed";
      const isFuture = phase.status === "future";
      const cls = isCurrent ? " roadmap-current" : isCompleted ? " completed" : "";
      const dotColor = isCurrent
        ? "var(--blue)"
        : isCompleted
          ? "var(--green)"
          : "var(--text-tertiary)";

      let gateHtml = "";
      if (phase.gateTests && phase.gateTests.length > 0) {
        // Use filtered results for current phase, all results for completed phases
        const evalResults = isCurrent ? currentPhaseResults : results;
        const evaluation = isFuture ? null : evaluateGateTests(phase.gateTests, evalResults);
        const gateItems = phase.gateTests
          .map((gateId) => {
            const name = benchmarks.find((bm) => bm.id === gateId)?.name ?? gateId;
            if (isFuture) {
              return `<div class="gate-item">${escapeHtml(name)}</div>`;
            }
            const test = evaluation!.tests.find((t) => t.benchmarkId === gateId);
            const icon = test?.passed ? "\u2713" : "\u2717";
            const itemCls = test?.passed ? "gate-passed" : "gate-not-passed";
            return `<div class="gate-item ${itemCls}">${icon} ${escapeHtml(name)}</div>`;
          })
          .join("\n");

        let allPassedBadge = "";
        if (evaluation?.allPassed && isCurrent) {
          allPassedBadge = `<div class="gate-all-passed">All gates passed \u2014 ready to advance</div>
<form data-on-submit__prevent="$$post('/api/advance-phase/${escapeAttr(phase.id)}')" style="margin-top:8px">
  <button type="submit" class="btn btn-sm btn-primary">Advance to Next Phase</button>
</form>`;
        } else if (evaluation?.allPassed && isCompleted) {
          allPassedBadge = `<div class="gate-all-passed">All gates passed</div>`;
        }

        gateHtml = `<div class="gate-checklist">
${gateItems}
${allPassedBadge}
</div>`;
      }

      return `<div class="roadmap-item${cls}"><div class="roadmap-indicator" style="background:${dotColor}"></div><div><div class="roadmap-name">${escapeHtml(phase.name)}</div>
    ${phase.weeks ? `<div class="roadmap-weeks">${escapeHtml(phase.weeks)}</div>` : ""}
    ${phase.summary ? `<div class="roadmap-summary">${escapeHtml(phase.summary)}</div>` : ""}
    ${gateHtml}
  </div>
</div>`;
    })
    .join("\n");

  return `<div class="section-header">Roadmap</div>
<div class="card">
${items}
</div>`;
}

/** Render a single benchmark card with results, trend, and log form. */
export function benchmarkCard(
  b: Benchmark,
  results: BenchmarkResultRow[],
  today: string
): string {
  const leftResults = results.filter((r) => r.side === "left");
  const rightResults = results.filter((r) => r.side === "right");
  const nullSideResults = results.filter((r) => r.side === null);
  const hasBilateral = leftResults.length > 0 || rightResults.length > 0;

  const latestResult =
    results.length > 0
      ? results.reduce((a, c) => (a.tested_at > c.tested_at ? a : c))
      : null;

  const retestDue = isRetestDue(latestResult?.tested_at ?? null, b.frequencyDays, today);

  const daysAgo =
    latestResult != null
      ? Math.floor(
          (new Date(today).getTime() - new Date(latestResult.tested_at).getTime()) /
            (1000 * 60 * 60 * 24)
        )
      : null;

  // Trend display
  let trendHtml: string;
  if (hasBilateral) {
    const leftTrend = formatTrend(leftResults);
    const rightTrend = formatTrend(rightResults);
    trendHtml = `<div class="benchmark-trend">L: ${escapeHtml(leftTrend)}</div>
<div class="benchmark-trend">R: ${escapeHtml(rightTrend)}</div>`;
  } else {
    trendHtml = `<div class="benchmark-trend">${escapeHtml(formatTrend(nullSideResults))}</div>`;
  }

  let retestHtml = "";
  if (retestDue) {
    retestHtml = `<div class="benchmark-retest">Due for retest</div>`;
  } else if (b.frequencyDays && latestResult) {
    const daysSince = daysAgo ?? 0;
    const daysUntil = b.frequencyDays - daysSince;
    if (daysUntil > 0) {
      retestHtml = `<div class="benchmark-retest-info">Retest due in ${daysUntil} day${daysUntil !== 1 ? "s" : ""}</div>`;
    }
  }

  const lastTestedHtml =
    daysAgo != null
      ? `<div class="benchmark-last-tested">Last tested: ${daysAgo} day${daysAgo !== 1 ? "s" : ""} ago</div>`
      : "";

  // Show side selector if already has bilateral results or target mentions "each side"
  const showSideSelector = hasBilateral || (b.target != null && /each side/i.test(b.target));

  // Log form — Datastar signals for toggle, $$post for SSE form submission
  const sig = `bench_${b.id.replace(/[^a-zA-Z0-9]/g, "_")}`;

  const formHtml = `<div data-signals-${sig}_open="false">
  <button class="btn btn-sm" data-on-click="$${sig}_open = !$${sig}_open">Log Result</button>
  <form data-show="$${sig}_open"
        data-on-submit__prevent="$$post('/api/log-benchmark/${escapeAttr(b.id)}')"
        style="margin-top:8px">
    <input type="text" name="value" placeholder="${escapeAttr(b.unit ?? "Value")}" required style="width:100%;margin-bottom:4px">
    ${showSideSelector ? `<select name="side" style="width:100%;margin-bottom:4px">
      <option value="">No side</option>
      <option value="left">Left</option>
      <option value="right">Right</option>
    </select>` : ""}
    <label style="display:flex;align-items:center;gap:4px;margin-bottom:4px">
      <input type="checkbox" name="passed" value="true"> Target met
    </label>
    <input type="text" name="notes" placeholder="Notes (optional)" style="width:100%;margin-bottom:4px">
    <button type="submit" class="btn btn-sm btn-primary">Save</button>
  </form>
</div>`;

  return `<div class="benchmark-item" id="benchmark-${escapeAttr(b.id)}">
  <div class="benchmark-name">${escapeHtml(b.name)}</div>
  ${b.target ? `<div class="benchmark-target">${escapeHtml(b.target)}</div>` : ""}
  ${trendHtml}
  ${lastTestedHtml}
  ${retestHtml}
  ${formHtml}
</div>`;
}

/**
 * Benchmarks section — list with name, target, trend, retest indicator, and log form.
 */
export function benchmarksSection(
  benchmarks: Benchmark[],
  results: BenchmarkResultRow[],
  today: string
): string {
  if (benchmarks.length === 0) return "";

  const items = benchmarks
    .map((b) => {
      const benchResults = results.filter((r) => r.benchmark_id === b.id);
      return benchmarkCard(b, benchResults, today);
    })
    .join("\n");

  return `<div class="section-header">Benchmarks</div>
<div class="card">
${items}
</div>`;
}

